class Solution {
public:
    int minStable(vector<int>& nums, int maxC) {
        int n = nums.size();
        int low = 1, high = n;
        int ans = 0;

        auto ok = [&](int len) -> bool {
            vector<int> dp(n + 1, 1e9);
            dp[0] = 0;
            for (int i = 1; i <= n; ++i) {
                int g = 0;
                for (int j = i - 1; j >= 0 && i - j <= len; --j) {
                    if (j < i - 1) g = gcd(g, nums[j]);
                    else g = nums[j];
                    if (g >= 2) {
                        dp[i] = min(dp[i], dp[j] + (i - j - 1));
                    }
                }
            }
            return dp[n] <= maxC;
        };

        while (low <= high) {
            int mid = (low + high) / 2;
            if (ok(mid)) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
};
